-- ITINERA v0.36 · estrutura por etapas + base documental 3
-- Ejecutar en Supabase SQL Editor.
-- Incluye: FP por familias, másteres/doctorados, guía por etapas, glosario, becas y mapas de continuidad.
begin;

create table if not exists public.itinera_life_stages (
  id text primary key,
  title text not null,
  subtitle text,
  content jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.itinera_glossary (
  id text primary key,
  term text not null,
  definition text not null,
  category text not null default 'xeral',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.itinera_scholarships (
  id text primary key,
  title text not null,
  body text not null,
  category text not null default 'becas',
  source_id text references public.itinera_sources(id) on delete set null,
  raw jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.itinera_route_maps (
  id text primary key,
  title text not null,
  steps jsonb not null default '[]'::jsonb,
  raw jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.itinera_fp_catalog_details (
  id text primary key,
  study_id text references public.itinera_studies(id) on delete cascade,
  learned text,
  work_context text,
  jobs jsonb not null default '[]'::jsonb,
  modules jsonb not null default '[]'::jsonb,
  source_file text,
  raw jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.itinera_postgraduate_catalog (
  id text primary key,
  study_id text references public.itinera_studies(id) on delete cascade,
  postgraduate_type text not null,
  campus text,
  source_file text,
  raw jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);


