insert into public.itinera_life_stages(id,title,subtitle,content)
values ('eso','Estou en ESO','Primeiras decisións académicas','{"id": "eso", "title": "Estou en ESO", "subtitle": "Primeiras decisións académicas", "where": "Estás nunha etapa obrigatoria na que empezan as primeiras bifurcacións reais: continuidade ordinaria, elección de materias, FP básica, Bacharelato ou FP de grao medio despois do título.", "options": ["Continuar ata obter o título de ESO.", "Explorar FP básica se hai unha necesidade de vía máis aplicada.", "Preparar Bacharelato se a meta é universidade ou FP superior.", "Preparar FP de grao medio se buscas unha vía profesional máis directa."], "decisions": ["Escoller materias que non pechen portas innecesariamente.", "Detectar se a dificultade é de interese, método, base académica ou circunstancias persoais.", "Usar LUMEN-V se non hai vocación clara."], "requirements": ["Para Bacharelato e FP de grao medio normalmente cómpre o título de ESO ou vías alternativas reguladas.", "Se non hai título, revisar educación de persoas adultas, FP básica ou probas de acceso cando proceda."], "next": ["LUMEN-V para intereses.", "Mapa ESO → Bacharelato / FP.", "Becas e NEAE se hai necesidades específicas."]}'::jsonb)
on conflict (id) do update set title=excluded.title,subtitle=excluded.subtitle,content=excluded.content,updated_at=now();


insert into public.itinera_life_stages(id,title,subtitle,content)
values ('bach','Estou en Bacharelato','Modalidade, materias e acceso','{"id": "bach", "title": "Estou en Bacharelato", "subtitle": "Modalidade, materias e acceso", "where": "Estás nunha etapa curta e decisiva. A modalidade e as materias poden influír na base académica, na ABAU e na admisión universitaria.", "options": ["Universidade mediante ABAU/EBAU.", "FP de grao superior.", "Ensinanzas artísticas, deportivas ou outras vías específicas.", "Reorientación cara a FP se o Bacharelato non encaixa."], "decisions": ["Escoller materias que ponderen e que tamén poidas preparar ben.", "Non confundir nota de corte con nota garantida.", "Comparar grao universitario e FP superior cando ambos levan a ámbitos próximos."], "requirements": ["Consultar ponderacións CIUG e notas de corte orientativas.", "Comprobar se o estudo require proba específica, idioma, praza limitada ou máster habilitante posterior."], "next": ["Simular ruta desde Bacharelato.", "Consultar ponderacións e becas.", "Comparar opcións universitarias e FP superior."]}'::jsonb)
on conflict (id) do update set title=excluded.title,subtitle=excluded.subtitle,content=excluded.content,updated_at=now();


insert into public.itinera_life_stages(id,title,subtitle,content)
values ('fp-start','Quero facer FP','Familias, ciclos, modalidade e saída profesional','{"id": "fp-start", "title": "Quero facer FP", "subtitle": "Familias, ciclos, modalidade e saída profesional", "where": "A FP é unha vía profesionalizante organizada por familias e módulos. Pode servir para traballar, especializarse ou continuar estudando.", "options": ["FP básica.", "Ciclo de grao medio.", "Ciclo de grao superior.", "Curso de especialización.", "Réxime ordinario, dual, modular, presencial, semipresencial ou a distancia segundo oferta."], "decisions": ["Escoller familia profesional antes que un título illado.", "Revisar centros, modalidade e prazas reais.", "Comprobar se o ciclo permite continuidade cara a un nivel superior."], "requirements": ["Acceso segundo nivel: ESO ou equivalente, Bacharelato, FP previa, proba de acceso ou outras vías reguladas.", "A oferta cambia por curso, centro e modalidade."], "next": ["Usar o selector por familias no simulador.", "Revisar ciclos modulares se necesitas compatibilidade con traballo ou vida familiar.", "Consultar saídas profesionais."]}'::jsonb)
