insert into public.itinera_life_stages(id,title,subtitle,content)
values ('fp-continue','Estou en FP e quero continuar','Do ciclo á especialización, grao superior ou universidade','{"id": "fp-continue", "title": "Estou en FP e quero continuar", "subtitle": "Do ciclo á especialización, grao superior ou universidade", "where": "Desde FP podes avanzar dentro da mesma familia, cambiar de familia, facer un grao superior, especializarte ou acceder á universidade desde un ciclo superior.", "options": ["Grao medio → grao superior.", "Grao superior → universidade.", "Grao superior → curso de especialización.", "Inserción laboral directa.", "Preparación de fase voluntaria se queres mellorar nota de admisión universitaria."], "decisions": ["Valorar se compensa facer fase voluntaria da ABAU.", "Escoller grao superior relacionado coa meta universitaria.", "Comprobar posibles convalidacións ou recoñecementos."], "requirements": ["A admisión á universidade desde FP superior depende de nota e prazas; a fase voluntaria pode mellorar opcións.", "Os cursos de especialización esixen títulos previos concretos."], "next": ["Simular ruta FP → universidade.", "Consultar cursos de especialización.", "Revisar emprego e becas."]}'::jsonb)
