insert into public.itinera_life_stages(id,title,subtitle,content)
values ('university-access','Quero ir á universidade','Graos, admisión, notas, campus e oficialidade','{"id": "university-access", "title": "Quero ir á universidade", "subtitle": "Graos, admisión, notas, campus e oficialidade", "where": "A universidade comeza polo grao, pero a decisión non debe quedar no nome do título. Hai que comprobar plan, campus, prazas, oficialidade, saídas e estudos posteriores.", "options": ["Acceso desde Bacharelato + ABAU.", "Acceso desde FP superior.", "Acceso por maiores de 25, 40 ou 45 segundo normativa.", "Cambio de grao, traslado ou segunda titulación."], "decisions": ["Comprobar se o título é oficial no RUCT.", "Revisar QEDU, plan de estudos, campus e prácticas.", "Identificar se require máster habilitante para exercer."], "requirements": ["Nota de admisión, prazas, criterios de prioridade, proba específica se existe e prazos da convocatoria.", "Becas e custo real de estudar fóra da casa."], "next": ["Buscar graos por universidade ou área.", "Consultar notas, ponderacións e becas.", "Ver mapas grao → máster → doutoramento."]}'::jsonb)
