insert into public.itinera_life_stages(id,title,subtitle,content)
values ('in-university','Xa estou na universidade','Reorientación, máster, doutoramento e saída profesional','{"id": "in-university", "title": "Xa estou na universidade", "subtitle": "Reorientación, máster, doutoramento e saída profesional", "where": "Se xa estás nun grao, a orientación tamén importa: podes continuar, cambiar, especializarte, preparar prácticas, opositar, facer máster ou iniciar investigación.", "options": ["Continuar no grao actual.", "Cambiar de grao ou universidade.", "Facer máster oficial ou habilitante.", "Facer doutoramento.", "Buscar prácticas, mobilidade ou saída profesional."], "decisions": ["Diferenciar cansazo puntual, falta de método e erro de elección.", "Revisar recoñecementos de créditos antes de cambiar.", "Planificar máster se a profesión o require."], "requirements": ["Normativa de permanencia, recoñecemento de créditos, requisitos de máster e prazos de admisión.", "Para doutoramento, liña de investigación, dirección e requisitos de acceso."], "next": ["Consultar másteres e doutoramentos.", "Revisar becas universitarias.", "Usar ItineraBot para comparar reorientacións."]}'::jsonb)
