insert into public.itinera_life_stages(id,title,subtitle,content)
values ('adult','Son persoa adulta e quero volver estudar','Vías flexibles, probas, modular e compatibilidade','{"id": "adult", "title": "Son persoa adulta e quero volver estudar", "subtitle": "Vías flexibles, probas, modular e compatibilidade", "where": "A orientación adulta debe partir do tempo dispoñible, titulación previa, experiencia laboral, responsabilidades e obxectivo: mellorar emprego, cambiar de sector ou iniciar estudos superiores.", "options": ["Educación de persoas adultas.", "Probas de acceso a grao medio ou superior.", "FP modular, semipresencial ou a distancia.", "Acceso á universidade para maiores de 25, 40 ou 45.", "Acreditación de competencias profesionais."], "decisions": ["Escoller unha ruta sostible, non só a máis rápida.", "Valorar matrícula por módulos se traballas ou tes responsabilidades familiares.", "Revisar becas, prazos e documentación."], "requirements": ["Idade, titulación previa, experiencia, prazos de inscrición e probas específicas segundo vía.", "Oferta real por curso e centro."], "next": ["Ver itinerarios modulares.", "Simular ruta flexible.", "Consultar becas e probas de acceso."]}'::jsonb)
