insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cm-guia-no-medio-natural-e-de-tempo-libre','fp-v36-cm-guia-no-medio-natural-e-de-tempo-libre','cos de baixo risco, medio acuático e instalacións de lecer e aventura, progre- sando a pé, con cordas, en bicicleta, en embarcacións e a cabalo, así como dinamizar actividades de tempo libre, adaptando todo iso aos participantes, respectando o medio ambiente e garantindo a calidade e a seguridade.','ra, así como en actividades socio educativas de tempo libre, nas áreas de organización, desenvolvemento, dinamización, seguimento e avalia- ción das devanditas actividades e nas de prevención, vixilancia e resca- te en espazos acuáticos naturais. Tamén poden exercer a súa actividade en unidades de intervención acuática e equipos de rescate e socorrismo. A actividade profesional realízase tanto de forma autónoma como contrata- da, no ámbito público, xa sexa administración xeral, autonómica ou local, e no ámbito privado, en grandes, medianas e pequenas empresas de servizos vinculadas aos sectores produtivos do deporte, turismo e lecer e tempo li- bre educativo infantil e xuvenil.','["cicleta por terreos de ata media montaña", "deseñador/a de itinerarios polo medio acuático en embarcacións de recreo exentas de despacho", "deseña- dor/a e organizador/a de actividades físicodeportivas recreativas guiadas polo medio natural", "encargado/a de prevención e seguridade en roteiros e eventos en bicicleta", "encargado/a de prevención e seguridade en roteiros e eventos ecuestres", "guía en actividades de sendeirismo", "montañismo por baixa e media montaña", "travesía por baixa e media montaña e roteiros ne- vados tipo nórdico con raquetas", "guía de barrancos de baixa dificultade", "guía de espeleoloxía de dificultade baixa", "guía de itinerarios en bicicleta de mon- taña", "guía de itinerarios de cicloturismo", "guía de itinerarios de cabalo", "guía de itinerarios polo medio acuático en embarcacións de recreo exentas de despacho", "monitor de tempo libre educativo infantil e xuvenil", "monitor/a de actividades no marco escolar", "monitor/a de instalacións de lecer e aventura", "socorrista en praias marítimas", "socorrista en lagos e encoros", "socorrista de apoio en unidades de intervención acuática"]'::jsonb,'[{"code": "MP1334", "name": "Guía de bicicleta", "hours": 158}, {"code": "MP0156", "name": "Inglés profesional", "hours": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP1339", "name": "Manobras con cordas", "hours": 209}, {"code": "MP1329", "name": "Organización de itinerarios", "hours": 130}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1325", "name": "Técnicas de equitación", "hours": 106}, {"code": "MP1336", "name": "Técnicas de natación", "hours": 53}, {"code": "MP1335", "name": "Técnicas de tempo libre", "hours": 107}, {"code": "MP1328", "name": "Atención a grupos", "hours": 82}, {"code": "MP1664", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1333", "name": "Guía de baixa e media montaña", "hours": 301}, {"code": "MP1327", "name": "Guía ecuestre", "hours": 109}, {"code": "MP1338", "name": "Guía no medio natural acuático", "hours": 164}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP1337", "name": "Socorrismo no medio natural", "hours": 164}]'::jsonb,'01-actividades_fisicas_e_deportivas_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
