insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cs-administracion-e-finanzas','fp-v36-cs-administracion-e-finanzas','cesos comerciais, laborais, contables, fiscais e financeiros dunha empresa pública ou privada, aplicando a normativa e os protocolos de xestión de ca- lidade, xestionando a información, asegurando a satisfacción da clientela e/ou dos usuarios, e actuando segundo as normas de prevención de riscos laborais e protección ambiental.','dade, nomeadamente no sector de servizos, así como na Administración Pública, desempeñando as tarefas administrativas na xestión e no aseso- ramento nas áreas laboral, comercial, contable e fiscal desas empresas e institucións, ofrecéndolles un servizo e atención á clientela e á cidadanía, realizando trámites administrativos coas administracións públicas e xes- tionando o arquivo e as comunicacións da empresa. Poderían traballar por conta propia, efectuando a xestión da súa propia empresa, ou a través do exercicio libre dunha actividade económica, como nunha asesoría financeira ou laboral, estudos de proxectos, etc.','["financeiro", "administrativo/a contable", "administrativo/a de loxística", "adminis- trativo/a de banca e de seguros", "administrativo/a de recursos humanos", "ad- ministrativo/a da Administración Pública", "administrativo/a de asesorías xu- rídicas, contables, laborais e fiscais, ou xestorías", "técnico/a en xestión de cobramentos", "responsable de atención á clientela."]'::jsonb,'[{"code": "MP0651", "name": "Comunicación e atención á clientela", "hours": 154}, {"code": "MP0179", "name": "Inglés profesional", "hours": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP0649", "name": "Ofimática e proceso da información", "hours": 237}, {"code": "MP0650", "name": "Proceso integral da actividade comercial", "hours": 128}, {"code": "MP0648", "name": "Recursos humanos e responsabilidade social corporativa", "hours": 77}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0647", "name": "Xestión da documentación xurídica e empresarial", "hours": 77}, {"code": "MP0654", "name": "Contabilidade e fiscalidade", "hours": 248}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0657", "name": "Proxecto intermodular de administración e finanzas", "hours": 50}, {"code": "MP0656", "name": "Simulación empresarial", "hours": 165}, {"code": "MP0652", "name": "Xestión de recursos humanos", "hours": 166}, {"code": "MP0653", "name": "Xestión financeira", "hours": 193}, {"code": "MP0655", "name": "Xestión loxística e comercial", "hours": 138}]'::jsonb,'02-administracion_e_xestion_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
