, {"code": "MP0832", "name": "Repoboacións forestais e tratamentos silvícolas", "hours": 210}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0833", "name": "Aproveitamento do medio natural", "hours": 301}, {"code": "MP0834", "name": "Conservación das especies cinexéticas e piscícolas", "hours": 164}, {"code": "MP0479", "name": "Control fitosanitario", "hours": 109}, {"code": "MP1664", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0836", "name": "Prevención de incendios forestais", "hours": 137}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP0838", "name": "Uso público en espazos naturais", "hours": 109}]'::jsonb,'03-agraria_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
