code": "MP0476", "name": "Produción agrícola", "hours": 273}, {"code": "MP0478", "name": "Produción de carne e outras producións gandeiras", "hours": 219}, {"code": "MP0477", "name": "Produción de leite, ovos e animais para vida", "hours": 219}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}]'::jsonb,'03-agraria_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
