urs": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP0409", "name": "Principios de sanidade vexetal", "hours": 80}, {"code": "MP0578", "name": "Produción de plantas e terróns de céspede en viveiro", "hours": 183}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0407", "name": "Taller e equipamentos de tracción", "hours": 131}, {"code": "MP0579", "name": "Composicións florais e con plantas", "hours": 220}, {"code": "MP0479", "name": "Control fitosanitario", "hours": 109}, {"code": "MP1664", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0580", "name": "Establecementos de floraría", "hours": 109}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0577", "name": "Mantemento e mellora de xardíns e zonas verdes", "hours": 273}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP0581", "name": "Técnicas de venda en xardinaría e floraría", "hours": 109}]'::jsonb,'03-agraria_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
