oxecto intermodular de gandaría e asistencia en sanidade ani-", "hours": 50}, {"code": "MP1279", "name": "Saneamento gandeiro", "hours": 191}, {"code": "MP1282", "name": "Xestión de centros veterinarios", "hours": 165}]'::jsonb,'03-agraria_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
