", "hours": 146}, {"code": "AM3162", "name": "Comunicación e ciencias sociais II", "hours": 125}, {"code": "MP3128", "name": "Manipulacións en industrias gráficas", "hours": 285}, {"code": "MP3126", "name": "Operacións de almacén en industrias gráficas", "hours": 164}, {"code": "MP3127", "name": "Operacións de produción gráfica", "hours": 285}, {"code": "MP3160", "name": "Proxecto intermodular de aprendizaxe colaborativa", "hours": 25}]'::jsonb,'04-artes_graficas_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
