 I", "hours": 107}, {"code": "MP0931", "name": "Márketing dixital", "hours": 181}, {"code": "MP0930", "name": "Políticas de márketing", "hours": 181}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0623", "name": "Xestión económica e financeira da empresa", "hours": 181}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0926", "name": "Escaparatismo e deseño de espazos comerciais", "hours": 165}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0625", "name": "Loxística de almacenamento", "hours": 165}, {"code": "MP0626", "name": "Loxística de aprovisionamento", "hours": 138}, {"code": "MP0928", "name": "Organización de equipos de vendas", "hours": 139}, {"code": "MP0932", "name": "Proxecto intermodular de xestión de vendas e espazos comerciais", "hours": 50}, {"code": "MP0929", "name": "Técnicas de venda e negociación", "hours": 138}, {"code": "MP0927", "name": "Xestión de produtos e promocións no punto de venda", "hours": 165}]'::jsonb,'05-comercio_e_marketing_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
