ode": "MP0361", "name": "Infraestruturas de redes de datos e sistemas de telefonía", "hours": 246}, {"code": "MP0238", "name": "Instalacións domóticas", "hours": 192}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}]'::jsonb,'07-electricidade_e_electronica_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
