 164}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}]'::jsonb,'07-electricidade_e_electronica_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
