istema produtivo", "hours": 30}, {"code": "MP0967", "name": "Comunicacións industriais", "hours": 246}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0968", "name": "Integración de sistemas de automatización industrial", "hours": 246}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0969", "name": "Proxecto intermodular de automatización e robótica industrial", "hours": 50}, {"code": "MP0966", "name": "Robótica industrial", "hours": 137}, {"code": "MP0965", "name": "Sistemas programables avanzados", "hours": 191}]'::jsonb,'07-electricidade_e_electronica_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
