insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cb-cocina-e-restauracion','fp-v36-cb-cocina-e-restauracion','de elaboracións culinarias sinxelas no ámbito da produción en cociña, así como as operacións de preparación e presentación de alimentos e bebidas en establecementos de restauración e catering, asistindo nos procesos de servizo e atención á clientela, seguindo os protocolos de calidade estable- cidos, cumprindo as normas de hixiene, prevención de riscos laborais e pro- tección ambiental, con responsabilidade e iniciativa persoal, e comunicán- dose oralmente e por escrito en linguas galega e castelá, así como nalgunha lingua estranxeira.','do sector da hostalaría, en establecementos de restauración, bares e ca- fetarías, en tendas especializadas en comidas preparadas e en empresas dedicadas ao almacenamento, o envasamento e a distribución de produtos alimenticios. Tamén poden traballar por conta propia en pequenos estable- cementos dos subsectores de hotelaría e restauración tradicional, moderna ou colectiva.','["produción e servizo de alimentos e bebidas", "auxiliar ou axudante de cama- reiro/a en sala", "auxiliar ou axudante/a de camareiro/a en bar-cafetaría", "auxi- liar ou axudante de barman"]'::jsonb,'[{"code": "MP3036", "name": "Aprovisionamento e conservación de materias primas e hixie-", "hours": 117}, {"code": "MP3005", "name": "Atención á clientela", "hours": 58}, {"code": "AM3163", "name": "Ciencias aplicadas I", "hours": 146}, {"code": "AM3161", "name": "Comunicación e ciencias sociais I", "hours": 175}, {"code": "MP3159", "name": "Itinerario persoal para a empregabilidade", "hours": 60}, {"code": "MP3035", "name": "Procesos básicos de produción culinaria", "hours": 179}, {"code": "MP3034", "name": "Técnicas elementais de preelaboración", "hours": 175}, {"code": "AM3164", "name": "Ciencias aplicadas II", "hours": 146}, {"code": "AM3162", "name": "Comunicación e ciencias sociais II", "hours": 125}, {"code": "MP3039", "name": "Preparación e montaxe de materiais para colectividades e", "hours": 163}, {"code": "MP3038", "name": "Procesos básicos de preparación de alimentos e bebidas", "hours": 286}, {"code": "MP3160", "name": "Proxecto intermodular de aprendizaxe colaborativa", "hours": 25}, {"code": "MP3037", "name": "Técnicas elementais de servizo", "hours": 285}]'::jsonb,'10-hostalaria_e_turismo_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
