utivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0045", "name": "Ofertas gastronómicas", "hours": 137}, {"code": "MP0048", "name": "Produtos culinarios", "hours": 492}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP0028", "name": "Sobremesas en restauración", "hours": 191}]'::jsonb,'10-hostalaria_e_turismo_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
