ca e descoloración da peluxe", "hours": 191}, {"code": "MP1664", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0643", "name": "Márketing e venda en imaxe persoal", "hours": 82}, {"code": "MP0642", "name": "Perfumaría e cosmética natural", "hours": 137}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP0637", "name": "Técnicas de uñas artificiais", "hours": 164}]'::jsonb,'12-imaxe_persoal_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
