name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1647", "name": "Proxecto intermodular de termalismo e benestar", "hours": 50}, {"code": "MP1152", "name": "Técnicas de hidrocinesia", "hours": 164}, {"code": "MP1136", "name": "Valoración da condición física e intervención en accidentes", "hours": 219}]'::jsonb,'12-imaxe_persoal_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
