insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cm-elaboracion-de-produtos-alimentarios','fp-v36-cm-elaboracion-de-produtos-alimentarios','alimentarios de acordo cos plans de produción e calidade, así como efectuar o mantemento de primeiro nivel dos equipamentos, aplicando a lexislación de hixiene e seguridade alimentaria, de protección ambiental e de preven- ción de riscos laborais.','pequenas, medianas ou grandes, con niveis moi diversos tanto na súa tecno- loxía como na súa organización. Son traballadores e traballadoras por conta allea que se integran nun equipo de traballo con persoas do seu mesmo nivel de cualificación, ou inferior, onde desenvolven tarefas individuais e en grupo nas áreas funcionais de recepción de materias primas e materiais, preparación e manexo de equipamentos de produción, control de operacións de elaboración, envasamento e embalaxe, apoio ao control de calidade, al- macenamento e expedición de produtos acabados. En xeral, dependerán or- ganicamente dun mando intermedio, coa excepción de pequenas empresas ou nas que aínda as operacións manuais posúan relevancia, nas que poden exercer funcións de supervisión de operarios e depender, no seu exercicio, directamente da dirección de produción.','["mentos para o tratamento e a elaboración de produtos alimentarios", "opera- dor/a e controlador/a de liñas de envasamento e embalaxe", "recepcionista e almaceneiro/a", "subministrador/a de materias primas e materiais ás liñas de produción", "dosificador/a", "supervisor/a de liña."]'::jsonb,'[{"code": "MP0156", "name": "Inglés profesional", "hours": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP0141", "name": "Materias primas na industria alimentaria", "hours": 236}, {"code": "MP0142", "name": "Operacións de acondicionamento de materias primas", "hours": 184}, {"code": "MP0030", "name": "Operacións e control de almacén na industria alimentaria", "hours": 80}, {"code": "MP0031", "name": "Seguridade e hixiene na manipulación de alimentos", "hours": 53}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0143", "name": "Tratamentos de transformación e conservación", "hours": 210}, {"code": "MP1664", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0116", "name": "Principios de mantemento electromecánico", "hours": 109}, {"code": "MP0144", "name": "Procesamento de produtos alimentarios", "hours": 274}, {"code": "MP0145", "name": "Procesos tecnolóxicos na industria alimentaria", "hours": 328}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP0146", "name": "Venda e comercialización de produtos alimentarios", "hours": 109}]'::jsonb,'13-industrias_alimentarias_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
