resentación e venda de produtos de panadaría e pastelaría", "hours": 82}, {"code": "MP0029", "name": "Produtos de obradoiro", "hours": 246}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP0028", "name": "Sobremesas en restauración", "hours": 191}]'::jsonb,'13-industrias_alimentarias_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
