inerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0085", "name": "Lexislación vitivinícola e seguridade alimentaria", "hours": 219}, {"code": "MP0087", "name": "Proxecto na industria vitivinícola", "hours": 50}, {"code": "MP0086", "name": "Xestión de calidade e ambiental na industria alimentaria", "hours": 109}]'::jsonb,'13-industrias_alimentarias_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
