values ('detail-fp-v36-cm-mantemento-e-control-de-maquinaria-de-buques-e-embarcacions','fp-v36-cm-mantemento-e-control-de-maquinaria-de-buques-e-embarcacions','pulsora e os equipamentos e sistemas do buque, e colaborar na seguridade, na supervivencia e na asistencia sanitaria a bordo, aplicando criterios de calidade e cumprindo os plans de prevención de riscos laborais e ambientais da empresa.','buques dedicados ao transporte marítimo de carga e pasaxe, ou en buques pesqueiros, de natureza pública ou privada, dentro dos lí- mites e as atribucións que estableza a Administración competente. Así mesmo, a súa formación permítelles desempeñar funcións por conta allea ou por conta propia en empresas dedicadas ao mantemento de embar- cacións e plantas enerxéticas.','["operario/a de reparación e mantemento de plantas enerxéticas de mo- tor e vapor", "xefe/a de máquinas", "oficial de máquinas ou primeiro/a oficial de máquinas", "mecánico/a de motores e equipamentos de inxección (diésel e ga- solina)", "mecánico/a de motores de gasolina", "mecánico/a de motores diésel", "mecánico/a de motores en maquinaria industrial", "mecánico/a de motores e grupos mecánicos navais en estaleiros", "mantedor/a de aire acondicionado e fluídos en embarcacións deportivas e de recreo", "electricista naval", "electri- cista de mantemento e reparación de motores, dínamos e transformado- res", "operario/a de instalación e mantemento de sistemas frigoríficos e de aire acondicionado."]'::jsonb,'[{"code": "MP1033", "name": "Atención sanitaria a bordo", "hours": 52}, {"code": "MP0156", "name": "Inglés profesional", "hours": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP1172", "name": "Mantemento da planta propulsora e maquinaria auxiliar", "hours": 233}, {"code": "MP1175", "name": "Mantemento das instalacións e máquinas eléctricas en bu-", "hours": 155}, {"code": "MP1173", "name": "Procedementos de mecanizado e soldadura en buques e em-", "hours": 233}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1664", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1176", "name": "Instalación e mantemento de maquinaria de frío e climatiza-", "hours": 276}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1177", "name": "Procedementos de garda de máquinas", "hours": 110}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP1174", "name": "Regulación e mantemento de automatismos en buques e em-", "hours": 276}, {"code": "MP1032", "name": "Seguridade marítima", "hours": 248}]'::jsonb,'18-maritimo_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
