insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cs-organizacion-do-mantemento-de-maquinaria-de-buques-e-embarcacions','fp-v36-cs-organizacion-do-mantemento-de-maquinaria-de-buques-e-embarcacions','ballos de mantemento da planta propulsora, maquinaria auxiliar e servizos do buque, a partir da información técnica, así como organizar o servizo de mantemento e montaxe deses elementos en embarcacións en terra, definin- do recursos, dirixindo equipos humanos e organizando e realizando as gar- das de máquinas, e realizar as tarefas de mantemento, regulación e control garantindo a seguridade da travesía en condicións de calidade e seguridade laboral e ambiental definidas.','de máquinas; primeiro oficial e xefe de máquinas en buques e embarcacións de buques civís e de pesca, así como en empresas públicas ou privadas de calquera tamaño dedicadas á construción, a reparación e o mantemento na- val, tanto por conta propia como allea. Así mesmo, poderán empregarse, por conta propia ou allea, en pequenas e medianas empresas, de natureza pú- blica ou privada, dedicadas á construción e o mantemento de embarcacións deportivas e de recreo. En determinadas circunstancias, deberán facer uso da lingua inglesa como vehículo de comunicación.','["co/a maior naval", "oficial de máquinas ou primeiro/a oficial de máquinas", "ins- pector/a en empresas pesqueiras", "encargado/a de taller de sistemas de propulsión e goberno de embarcacións deportivas e de recreo", "perito/a ta- xador/a de embarcacións deportivas e de recreo."]'::jsonb,'[{"code": "MP0179", "name": "Inglés profesional", "hours": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP0802", "name": "Organización da asistencia sanitaria a bordo", "hours": 52}, {"code": "MP1308", "name": "Organización do mantemento de planta propulsora e maqui-", "hours": 233}, {"code": "MP1311", "name": "Organización do mantemento e da montaxe de instalacións e", "hours": 181}, {"code": "MP1309", "name": "Organización do mantemento en seco de buques e embarca-", "hours": 207}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0800", "name": "Control das emerxencias", "hours": 248}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1314", "name": "Organización da garda de máquinas", "hours": 83}, {"code": "MP1312", "name": "frigoríficas e sistemas de climatización de buques e embar-", "hours": 248}, {"code": "MP1313", "name": "Planificación do mantemento de maquinaria de buques e em-", "hours": 83}, {"code": "MP1310", "name": "Programación e mantemento de automatismos hidráulicos e", "hours": 248}]'::jsonb,'18-maritimo_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
