insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cs-transporte-maritimo-e-pesca-de-altura','fp-v36-cs-transporte-maritimo-e-pesca-de-altura','determinen as administracións competentes para este nivel, dirixindo e con- trolando a seguridade, a navegación, as manobras e as operacións de carga, estiba e descarga, así como a extracción, a manipulación, o procesamento e a conservación da pesca, optimizando a produción e cumprindo a normativa estatal e internacional.','en buques pesqueiros, de natureza pública ou privada, dentro dos límites e das atribucións que estableza a Administración competente. A actividade profesional está sometida a regulación pola Administración competente. Así mesmo, a súa formación permítelle desempeñar funcións do seu nivel desembarcado, en empresas e entidades pertencentes ao sector marítimo pesqueiro.','["mando de buques de pesca, buques mercantes de carga e de pasaxe, e iates de gran eslora", "primeiro/a oficial de ponte", "oficial de ponte en buques de pesca, buques mercantes de carga e de pasaxe, e iates de gran eslora", "inspector/a de flota", "axente de consignatarias", "axente de seguros marítimos", "supervisor/a de montaxe e armaxe de artes e aparellos de pesca."]'::jsonb,'[{"code": "MP0803", "name": "Administración e xestión do buque e da actividade pesqueira", "hours": 129}, {"code": "MP0179", "name": "Inglés profesional", "hours": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP0798", "name": "Manobra e estiba", "hours": 233}, {"code": "MP0799", "name": "Navegación, goberno e comunicacións do buque", "hours": 259}, {"code": "MP0802", "name": "Organización da asistencia sanitaria a bordo", "hours": 52}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0800", "name": "Control das emerxencias", "hours": 248}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0804", "name": "Garda de ponte", "hours": 331}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0805", "name": "Pesca de altura e grande altura", "hours": 331}, {"code": "MP0808", "name": "Proxecto intermodular de implementación dunha ruta de trans-", "hours": 50}]'::jsonb,'18-maritimo_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
