e": "Codificación sanitaria", "hours": 301}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1524", "name": "Proxecto intermodular de documentación e administración sa-", "hours": 50}, {"code": "MP1519", "name": "Sistemas de información e clasificación sanitarios", "hours": 109}, {"code": "MP1522", "name": "Validación e explotación de datos", "hours": 164}, {"code": "MP1523", "name": "Xestión administrativa sanitaria", "hours": 164}, {"code": "MP1515", "name": "Xestión de pacientes", "hours": 82}]'::jsonb,'20-sanidade_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
