insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cs-laboratorio-clinico-e-biomedico','fp-v36-cs-laboratorio-clinico-e-biomedico','normalizados de traballo, aplicando as normas de calidade, seguridade e ambientais establecidas, e valorando os resultados técnicos, para que sir- van como soporte á prevención, ao diagnóstico, ao control da evolución e ao tratamento da doenza, así como á investigación, seguindo os protocolos establecidos na unidade asistencial.','empresas privadas, na área do laboratorio de análises clínicas, así como no diagnóstico, no tratamento, na xestión e na investigación. Actúan como traballadores/as dependentes en organismos ou institucións pequenos, me- dianos ou grandes. A súa actividade profesional está sometida a regulación pola Administración sanitaria estatal.','["lista en laboratorio", "axudante/a técnico en laboratorio de investigación e ex- perimentación", "axudante/a técnico en laboratorio de toxicoloxía", "delegado/a comercial de produtos hospitalarios e farmacéuticos."]'::jsonb,'[{"code": "MP1369", "name": "Bioloxía molecular e citoxenética", "hours": 157}, {"code": "MP1370", "name": "Fisiopatoloxía xeral", "hours": 183}, {"code": "MP0179", "name": "Inglés profesional", "hours": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1368", "name": "Técnicas xerais de laboratorio", "hours": 240}, {"code": "MP1367", "name": "Xestión de mostras biolóxicas", "hours": 183}, {"code": "MP1371", "name": "Análise bioquímica", "hours": 246}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1373", "name": "Microbioloxía clínica", "hours": 219}, {"code": "MP1375", "name": "Proxecto intermodular de laboratorio clínico e biomédico", "hours": 50}, {"code": "MP1374", "name": "Técnicas de análise hematolóxica", "hours": 246}, {"code": "MP1372", "name": "Técnicas de inmunodiagnóstico", "hours": 109}]'::jsonb,'20-sanidade_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
