sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0858", "name": "Próteses parciais removibles metálicas, de resina e mixtas", "hours": 301}, {"code": "MP0860", "name": "Próteses sobre implantes", "hours": 218}, {"code": "MP0861", "name": "Proxecto intermodular de próteses dentais", "hours": 50}, {"code": "MP0859", "name": "Restauracións e recubrimentos estéticos", "hours": 301}]'::jsonb,'20-sanidade_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
