insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cm-emerxencias-e-proteccion-civil','fp-v36-cm-emerxencias-e-proteccion-civil','xencias provocadas por sucesos ou catástrofes orixinadas por riscos diver- sos, en áreas tanto rurais e forestais como urbanas, realizando as activida- des de control, mitigación e extinción dos axentes causantes deses sucesos (lume, avenidas de auga, substancias NBQ, etc.), o rescate, o salvamento e a atención como primeiro interveniente das persoas afectadas e a rehabilita- ción de emerxencia das zonas ou os bens abranguidos, mantendo operativos os vehículos, os equipamentos, as máquinas e as ferramentas de interven- ción, así como organizar os equipos e as unidades baixo a súa responsa- bilidade, e contribuír á divulgación e ao cumprimento dos principios e as normas de protección civil, aplicando a normativa vixente.','apoio en continxencias do medio natural e rural e Protección Civil, así como nos servizos públicos estatais, autonómicos e locais de atención de emer- xencias e os corpos de bombeiros, desenvolvendo a súa actividade como traballador/a dependente das administracións públicas ou en empresas pri- vadas dedicadas a traballos agroforestais e ambientais, en servizos de bom- beiros/as dedicados á prevención de incendios e mantemento, e en sectores industriais dedicados á produción, á distribución, á fabricación e ao almace- namento de produtos e substancias perigosas, podendo exercer accións de colaboración internacional.','["técnico/a en emerxen- cias das Forzas Armadas", "bombeiro/a de aeroportos ou de empresa privada."]'::jsonb,'[{"code": "MP0058", "name": "Apoio psicolóxico en situacións de emerxencia", "hours": 53}, {"code": "MP0055", "name": "Atención sanitaria inicial en situacións de emerxencia", "hours": 206}, {"code": "MP0156", "name": "Inglés profesional", "hours": 60}, {"code": "MP1532", "name": "Intervención operativa en actividades de salvamento e res-", "hours": 214}, {"code": "MP1530", "name": "Intervención operativa en extinción de incendios urbanos", "hours": 160}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP1528", "name": "materiais empregados na prevención de riscos de incendios", "hours": 130}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1534", "name": "Coordinación de equipos e unidades de emerxencias", "hours": 137}, {"code": "MP1664", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1533", "name": "Inspección de establecementos, eventos e instalacións para a", "hours": 109}, {"code": "MP1531", "name": "Intervención operativa en sucesos de orixe natural, tecno-", "hours": 273}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1713", "name": "Proxecto intermodular", "hours": 50}, {"code": "MP1529", "name": "Vixilancia e intervención operativa en incendios forestais", "hours": 301}]'::jsonb,'21-seguridade_e_medio_ambiente_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
