{"code": "MP1414", "name": "Riscos químicos e biolóxicos ambientais", "hours": 219}, {"code": "MP1418", "name": "Ruídos e vibracións", "hours": 136}, {"code": "MP1419", "name": "Xestión da prevención e responsabilidade xurídica", "hours": 219}]'::jsonb,'21-seguridade_e_medio_ambiente_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
