uridade alimentaria", "hours": 300}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1555", "name": "Proxecto intermodular de química e saúde ambiental", "hours": 50}, {"code": "MP1550", "name": "Saúde e riscos do medio construído", "hours": 164}, {"code": "MP1554", "name": "Unidade de saúde ambiental", "hours": 137}]'::jsonb,'21-seguridade_e_medio_ambiente_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
