insert into public.itinera_fp_catalog_details(id,study_id,learned,work_context,jobs,modules,source_file,raw)
values ('detail-fp-v36-cs-formacion-para-a-mobilidade-segura-e-sostible','fp-v36-cs-formacion-para-a-mobilidade-segura-e-sostible','incluíndo a relativa á convivencia cos distintos modos de transporte e o seu uso en condicións de seguridade e sustentabilidade ambiental, así como á mobilidade nas vías públicas, incluíndo a relativa á convivencia cos distintos modos de transporte e o seu uso en condicións de seguridade, formando e sensibilizando aspirantes á obtención do permiso ou a licenza de condu- ción, a condutores e condutoras e, en xeral, a calquera persoa usuaria da vía, educando en valores de seguridade viaria e sustentabilidade ambiental do transporte e instruíndo en prevención de accidentes viarios laborais e en mobilidade sustentable e segura.','medianas e grandes empresas dedicadas á formación de condutores e con- dutoras para a obtención das autorizacións administrativas para conducir e, en xeral, á formación para a seguridade viaria. Tamén poderán exercer funcións relacionadas coa educación viaria, a seguridade viaria laboral e a mobilidade segura e sustentable, en entidades públicas e privadas.','["mador/a de cursos de sensibilización e reeducación viaria", "formador/a de cursos de mercadorías perigosas", "director/a de centros de formación de mercadorías perigosas", "asesor/a de seguridade viaria laboral en entidades públicas e priva- das", "asesor/a en plans de mobilidade en entidades públicas e privadas", "do- cente en seguridade viaria", "monitor/a de cursos de condución segura."]'::jsonb,'[{"code": "MP1658", "name": "Didáctica da formación para a seguridade viaria", "hours": 106}, {"code": "MP1656", "name": "Educación viaria", "hours": 151}, {"code": "MP0179", "name": "Inglés profesional", "hours": 60}, {"code": "MP1709", "name": "Itinerario persoal para a empregabilidade I", "hours": 107}, {"code": "MP1657", "name": "Seguridade viaria", "hours": 178}, {"code": "MP1708", "name": "Sostibilidade aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1653", "name": "Técnicas de condución", "hours": 76}, {"code": "MP1654", "name": "Tecnoloxía básica do automóbil", "hours": 50}, {"code": "MP1651", "name": "Tráfico, circulación de vehículos e transporte por estrada", "hours": 202}, {"code": "MP1655", "name": "Didáctica do ensino práctico da condución", "hours": 437}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP1659", "name": "Mobilidade segura e sostible", "hours": 164}, {"code": "MP1652", "name": "Organización da formación das persoas condutoras", "hours": 137}, {"code": "MP0020", "name": "Primeiros auxilios", "hours": 82}, {"code": "MP1660", "name": "Proxecto intermodular de formación para a mobilidade segura e", "hours": 50}]'::jsonb,'22-servizos_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
