rs": 30}, {"code": "MP0341", "name": "Apoio á intervención educativa", "hours": 164}, {"code": "MP1665", "name": "Dixitalización aplicada ao sistema produtivo", "hours": 30}, {"code": "MP0017", "name": "Habilidades sociais", "hours": 164}, {"code": "MP1710", "name": "Itinerario persoal para a empregabilidade II", "hours": 50}, {"code": "MP0340", "name": "Mediación comunitaria", "hours": 219}, {"code": "MP0020", "name": "Primeiros auxilios", "hours": 82}, {"code": "MP0345", "name": "Proxecto intermodular de integración social", "hours": 50}, {"code": "MP0343", "name": "Sistemas aumentativos e alternativos de comunicación", "hours": 191}]'::jsonb,'22-servizos_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
