values ('detail-fp-v36-cb-tapizaria-e-cortinaxe','fp-v36-cb-tapizaria-e-cortinaxe','e outros elementos de decoración, cortando, marcando e ensamblando os materiais, aproveitándoos ao máximo e conseguindo produtos coa estética e o acabamento requiridos, operando coa calidade indicada, cumprindo as normas de prevención de riscos laborais e protección ambiental correspon- dentes, e comunicándose oralmente e por escrito en linguas galega e caste- lá, así como nalgunha lingua estranxeira.','que se dedican a tapizar mobles, entear superficies, confeccionar toldos e fabricar e instalar produtos aplicados ao téxtil do fogar.','["liar", "tapiceiro/a de vehículos", "enteador/a", "reparador/a de toldos", "operador/a de máquinas industriais de coser e bordar", "montador/a de cortinaxes e de estores."]'::jsonb,'[{"code": "AM3163", "name": "Ciencias aplicadas I", "hours": 146}, {"code": "AM3161", "name": "Comunicación e ciencias sociais I", "hours": 175}, {"code": "MP3101", "name": "Confección de artigos téxtiles para decoración", "hours": 204}, {"code": "MP3100", "name": "Confección e montaxe de cortinas e estores", "hours": 237}, {"code": "MP3159", "name": "Itinerario persoal para a empregabilidade", "hours": 60}, {"code": "MP3077", "name": "Materiais e produtos téxtiles", "hours": 88}, {"code": "MP3005", "name": "Atención á clientela", "hours": 122}, {"code": "AM3164", "name": "Ciencias aplicadas II", "hours": 146}, {"code": "AM3162", "name": "Comunicación e ciencias sociais II", "hours": 125}, {"code": "MP3160", "name": "Proxecto intermodular de aprendizaxe colaborativa", "hours": 25}, {"code": "MP3078", "name": "Tapizado de mobles", "hours": 285}, {"code": "MP3099", "name": "Tapizado de murais e enteamento de superficies", "hours": 327}]'::jsonb,'23-textil_v7.pdf',jsonb_build_object('source_upload','3 base de datos itinera.zip','duration_hours','2000'))
